import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ToxicityLevel {
  SAFE = 'SAFE',
  MILD = 'MILD',
  TOXIC = 'TOXIC',
  HIGHLY_TOXIC = 'HIGHLY_TOXIC',
  EXTREME = 'EXTREME'
}

export interface Highlight {
  word: string;
  category: string;
}

export interface ToxicityResult {
  score: number;
  level: ToxicityLevel;
  detectedLanguage: string;
  categories: string[];
  highlights: Highlight[];
  timestamp: number;
  originalText: string;
}

export interface HistoryItem extends ToxicityResult {
  id: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ToxicityResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeToxicity = async (text: string, language: string): Promise<ToxicityResult> => {
  const systemInstruction = `
    You are an advanced game chat moderation system named Sentinel AI. 
    Analyze the provided chat text for toxicity across various dimensions.

    Dimensions to check: 
    - hate_speech: content that attacks people based on race, religion, etc.
    - harassment: repeated attacks or insults.
    - profanity: swear words or vulgar language.
    - threat: physical or hacking threats.
    - racism: specific racial slurs or discriminatory themes.
    - bullying: targeting specific players or noob-shaming.
    - sexual_content: sexually explicit language.
    - spam: repetitive meaningless text.

    If the user chose "auto" for language, identify it.

    Return a valid JSON object with:
    - score: integer from 0 to 100 representing overall toxicity.
    - level: one of ["SAFE", "MILD", "TOXIC", "HIGHLY_TOXIC", "EXTREME"].
    - detectedLanguage: short string like "English", "Spanish", etc.
    - categories: array of detected category IDs from the list above.
    - highlights: array of objects { "word": string, "category": string } for specific problematic spans.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this chat text (${language === 'auto' ? 'Auto-detect' : 'Forcing Language: ' + language}): "${text}"`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.INTEGER },
            level: { type: Type.STRING },
            detectedLanguage: { type: Type.STRING },
            categories: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            highlights: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  word: { type: Type.STRING },
                  category: { type: Type.STRING }
                },
                required: ["word", "category"]
              }
            }
          },
          required: ["score", "level", "detectedLanguage", "categories", "highlights"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return {
      ...result,
      timestamp: Date.now(),
      originalText: text
    };
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw new Error("Failed to analyze text. Please check your connection and try again.");
  }
};

import React, { useEffect, useRef } from 'react';

const StarBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let stars: any[] = [];
    const numStars = 150;

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      stars = [];
      for (let i = 0; i < numStars; i++) {
        stars.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          size: Math.random() * 2,
          speed: Math.random() * 0.3 + 0.1,
          opacity: Math.random()
        });
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      stars.forEach(star => {
        ctx.fillStyle = `rgba(255, 255, 255, ${star.opacity})`;
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
        ctx.fill();

        star.y += star.speed;
        star.opacity = Math.random() * 0.4 + 0.2;
        if (star.y > canvas.height) {
          star.y = 0;
          star.x = Math.random() * canvas.width;
        }
      });
      animationFrameId = requestAnimationFrame(draw);
    };

    init();
    draw();

    window.addEventListener('resize', init);
    return () => {
      window.removeEventListener('resize', init);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <>
      <div className="nebula top-[-10%] left-[-10%]" style={{ background: 'radial-gradient(circle, rgba(188, 19, 254, 0.1) 0%, rgba(5, 7, 20, 0) 70%)' }}></div>
      <div className="nebula bottom-[-10%] right-[-10%]" style={{ background: 'radial-gradient(circle, rgba(0, 243, 255, 0.1) 0%, rgba(5, 7, 20, 0) 70%)' }}></div>
      <canvas ref={canvasRef} className="fixed inset-0 z-[-1]" />
    </>
  );
};

export default StarBackground;

import React from 'react';
import { THEME } from '../constants.tsx';

interface GaugeProps {
  score: number;
  color: string;
}

const Gauge: React.FC<GaugeProps> = ({ score, color }) => {
  const radius = 45;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (score / 100) * circumference;

  return (
    <div className="relative w-32 h-32 mx-auto mb-2">
      <svg className="w-full h-full transform -rotate-90" viewBox="0 0 100 100">
        <circle
          className="stroke-gray-800 fill-none"
          strokeWidth="10"
          cx="50"
          cy="50"
          r={radius}
        />
        <circle
          className="fill-none transition-all duration-1000 ease-out"
          stroke={color}
          strokeWidth="10"
          strokeDasharray={circumference}
          strokeDashoffset={offset}
          strokeLinecap="round"
          cx="50"
          cy="50"
          r={radius}
        />
      </svg>
      <div className="absolute inset-0 flex flex-col items-center justify-center font-orbitron">
        <span className="text-2xl font-bold" style={{ color }}>{score}%</span>
      </div>
    </div>
  );
};

export default Gauge;

import React, { useState, useEffect, useCallback } from 'react';
import StarBackground from './components/StarBackground';
import Gauge from './components/Gauge';
import { analyzeToxicity } from './services/geminiService';
import { ToxicityResult, HistoryItem, ToxicityLevel } from './types';
import { CATEGORIES, LANGUAGES, THEME } from './constants.tsx';

const App: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [language, setLanguage] = useState('auto');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ToxicityResult | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);

  const handleAnalyze = async () => {
    if (!inputText.trim() || loading) return;

    setLoading(true);
    try {
      const analysisResult = await analyzeToxicity(inputText, language);
      setResult(analysisResult);

      const newHistoryItem: HistoryItem = {
        ...analysisResult,
        id: crypto.randomUUID()
      };
      setHistory(prev => [newHistoryItem, ...prev].slice(0, 10));
    } catch (err: any) {
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  const getLevelColor = (level: ToxicityLevel) => {
    switch (level) {
      case ToxicityLevel.SAFE: return THEME.green;
      case ToxicityLevel.MILD: return THEME.orange;
      case ToxicityLevel.TOXIC: return THEME.red;
      case ToxicityLevel.HIGHLY_TOXIC: return '#ff3300';
      case ToxicityLevel.EXTREME: return THEME.red;
      default: return THEME.green;
    }
  };

  const renderHighlightedText = () => {
    if (!result) return <span className="text-gray-500 italic">Analysis spans will appear here...</span>;

    let text = result.originalText;
    const parts: React.ReactNode[] = [];
    let lastIndex = 0;

    // Sorting highlights to process them in order
    const sortedHighlights = [...result.highlights].sort((a, b) => {
        return text.indexOf(a.word, lastIndex) - text.indexOf(b.word, lastIndex);
    });

    sortedHighlights.forEach((h, idx) => {
      const index = text.indexOf(h.word, lastIndex);
      if (index !== -1) {
        parts.push(text.substring(lastIndex, index));
        parts.push(
          <span 
            key={idx} 
            className="font-bold border-b border-dashed" 
            style={{ color: THEME.red, borderColor: THEME.red, textShadow: `0 0 5px ${THEME.red}80` }}
            title={h.category}
          >
            {h.word}
          </span>
        );
        lastIndex = index + h.word.length;
      }
    });
    parts.push(text.substring(lastIndex));
    return parts;
  };

  const copyResults = () => {
    if (!result) return;
    const summary = `Sentiment Analysis: ${result.level} (${result.score}%)\nCategories: ${result.categories.join(', ')}\nText: ${result.originalText}`;
    navigator.clipboard.writeText(summary).then(() => alert('Copied to clipboard!'));
  };

  const exportReport = () => {
    if (history.length === 0) return;
    let content = "SENTINEL AI - TOXICITY REPORT\n" + "=".repeat(30) + "\n\n";
    history.forEach((h, i) => {
      content += `#${i+1} [${new Date(h.timestamp).toLocaleTimeString()}]\n`;
      content += `Score: ${h.score}% (${h.level})\n`;
      content += `Language: ${h.detectedLanguage}\n`;
      content += `Text: ${h.originalText}\n`;
      content += "-".repeat(30) + "\n";
    });
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'toxicity_report.txt';
    link.click();
  };

  return (
    <div className="min-h-screen relative pb-10">
      <StarBackground />

      <header className="pt-12 pb-8 text-center px-4">
        <div className="mb-4 inline-block">
          <i className={`fas fa-shield-halved text-5xl text-cyan-400 drop-shadow-[0_0_10px_#00f3ff] ${loading ? 'animate-pulse' : ''}`}></i>
        </div>
        <h1 className="font-orbitron text-4xl md:text-5xl font-black uppercase tracking-widest bg-gradient-to-r from-cyan-400 to-purple-500 bg-clip-text text-transparent drop-shadow-lg">
          Sentinel AI
        </h1>
        <p className="text-gray-400 mt-2 font-medium">Advanced Multi-Language Game Chat Moderation</p>
      </header>

      <main className="container mx-auto px-4 grid grid-cols-1 lg:grid-cols-2 gap-6 max-w-7xl">
        {/* Input Panel */}
        <section className="bg-opacity-70 bg-[#101428] backdrop-blur-md border border-white/10 rounded-2xl p-6 shadow-2xl hover:border-purple-500/50 transition-all">
          <div className="flex items-center gap-3 mb-6">
            <i className="fas fa-keyboard text-cyan-400"></i>
            <h2 className="font-orbitron text-xl uppercase tracking-wider text-cyan-400">Chat Input</h2>
          </div>

          <div className="flex flex-wrap gap-2 mb-4">
            <select 
              value={language}
              onChange={(e) => setLanguage(e.target.value)}
              className="bg-black/40 border border-blue-600/50 text-white px-3 py-2 rounded-lg font-orbitron text-xs focus:ring-1 focus:ring-cyan-400 outline-none"
            >
              {LANGUAGES.map(lang => (
                <option key={lang.value} value={lang.value}>{lang.flag} {lang.label}</option>
              ))}
            </select>
            <button 
              onClick={() => setInputText("You absolute trash player, your skill is non-existent. Go uninstall and stop wasting everyone's time you idiot.")}
              className="bg-black/40 border border-blue-600/50 text-white px-3 py-2 rounded-lg font-orbitron text-xs hover:bg-white/5"
            >
              Demo
            </button>
            <button 
              onClick={() => { setInputText(''); setResult(null); }}
              className="bg-black/40 border border-blue-600/50 text-white px-3 py-2 rounded-lg font-orbitron text-xs hover:bg-white/5"
            >
              Clear
            </button>
          </div>

          <textarea 
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="Paste game chat messages here to analyze..."
            className="w-full h-48 bg-black/60 border border-white/10 rounded-xl p-4 text-white focus:border-cyan-400 focus:ring-1 focus:ring-cyan-400 outline-none transition-all resize-none mb-4"
          />

          <button 
            onClick={handleAnalyze}
            disabled={loading}
            className="w-full py-4 rounded-xl font-orbitron font-bold text-lg tracking-wider flex items-center justify-center gap-3 bg-gradient-to-r from-blue-600 to-purple-600 hover:shadow-[0_0_20px_rgba(188,19,254,0.4)] transform hover:-translate-y-1 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {loading ? <i className="fas fa-spinner animate-spin"></i> : <i className="fas fa-microchip"></i>}
            {loading ? 'Analyzing...' : 'Analyze Toxicity'}
          </button>

          <div className="mt-6 p-4 bg-black/40 rounded-xl border border-white/5 min-h-[80px]">
            <p className="leading-relaxed">
              {renderHighlightedText()}
            </p>
          </div>
        </section>

        {/* Dashboard Panel */}
        <section className="bg-opacity-70 bg-[#101428] backdrop-blur-md border border-white/10 rounded-2xl p-6 shadow-2xl hover:border-purple-500/50 transition-all">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-3">
              <i className="fas fa-chart-pie text-cyan-400"></i>
              <h2 className="font-orbitron text-xl uppercase tracking-wider text-cyan-400">Analysis Dashboard</h2>
            </div>
            <div className="flex gap-2">
              <button onClick={copyResults} className="text-gray-400 hover:text-white transition-colors" title="Copy results"><i className="fas fa-copy"></i></button>
              <button onClick={exportReport} className="text-gray-400 hover:text-white transition-colors" title="Export report"><i className="fas fa-file-export"></i></button>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            <div className="bg-black/30 rounded-2xl p-6 text-center border border-white/5">
              <Gauge 
                score={result?.score || 0} 
                color={result ? getLevelColor(result.level) : THEME.green} 
              />
              <div 
                className="font-orbitron text-xl font-black mb-1 transition-colors duration-500"
                style={{ color: result ? getLevelColor(result.level) : THEME.green }}
              >
                {result?.level || 'AWAITING'}
              </div>
              <div className="text-xs text-gray-500 uppercase tracking-tighter">
                Language: <span className="text-cyan-400">{result?.detectedLanguage || '-'}</span>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-2">
              {CATEGORIES.map(cat => {
                const isActive = result?.categories.includes(cat.id);
                return (
                  <div 
                    key={cat.id}
                    className={`flex items-center gap-3 px-3 py-2 rounded-lg text-sm border-l-4 transition-all duration-300 ${isActive ? 'bg-red-500/10 border-red-500 text-red-200 shadow-[0_0_10px_rgba(255,0,85,0.2)]' : 'bg-white/5 border-transparent text-gray-500'}`}
                  >
                    <span className={isActive ? 'text-red-500' : ''}>{cat.icon}</span>
                    <span className="font-medium">{cat.label}</span>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="mt-8">
            <h3 className="font-orbitron text-sm text-gray-500 uppercase mb-4 tracking-widest flex items-center gap-2">
              <i className="fas fa-history"></i> Recent History
            </h3>
            <div className="space-y-3 max-h-[220px] overflow-y-auto pr-2">
              {history.length === 0 ? (
                <div className="text-center py-6 text-gray-600 italic text-sm">No analysis history yet.</div>
              ) : (
                history.map(item => (
                  <div 
                    key={item.id} 
                    className="flex items-center justify-between bg-black/40 border-l-4 p-3 rounded-lg hover:bg-black/60 transition-all"
                    style={{ borderColor: getLevelColor(item.level) }}
                  >
                    <div className="flex-1 min-w-0 mr-4">
                      <div className="text-xs text-gray-500 flex gap-2">
                        <span>{new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                        <span className="text-cyan-600 font-bold uppercase">{item.detectedLanguage}</span>
                      </div>
                      <p className="text-sm truncate text-gray-300">{item.originalText}</p>
                    </div>
                    <div className="font-orbitron font-bold text-sm" style={{ color: getLevelColor(item.level) }}>
                      {item.score}%
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </section>
      </main>

      <footer className="mt-12 text-center text-gray-600 text-xs px-4">
        <p>© 2025 SENTINEL AI SYSTEMS | POWERED BY GEMINI 3 FLASH</p>
      </footer>
    </div>
  );
};

export default App;
